    .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "RegionEncoded", "PurchaseHistory"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

// Evaluate only when the dataset is large enough for meaningful metrics
long rowCount = data.GetColumn<bool>("Label").Count();
if (rowCount >= 20)
{
    var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2);
    var evalModel = pipeline.Fit(split.TrainSet);
    var predictions = evalModel.Transform(split.TestSet);
    var metrics = mlContext.BinaryClassification.Evaluate(predictions);
    Console.WriteLine($"Accuracy: {metrics.Accuracy:F4}, AUC: {metrics.AreaUnderRocCurve:F4}, F1: {metrics.F1Score:F4}");
}
else
{
    Console.WriteLine($"Dataset has {rowCount} rows — skipping evaluation (need ≥20 for reliable metrics).");
}

// Train final model on all available data
var model = pipeline.Fit(data);

